#include <bits/stdc++.h>
#define R register
using namespace std;

const int N=5e4+4;

struct Edge{
	int to;
	long long val;
};

struct Node{
	int u,v,w;
}edge[N];

bool operator<(Edge x,Edge y){
	return x.val>y.val;
}

bool operator<(Node x,Node y){
	return x.w<y.w;
}

int n,m,a[N],dep[N],d[N],top;
bool b[N];
long long f[N][20],dis[N][20],mn[N];
int head[N],nxt[N<<1],tot;
Edge ver[N<<1];
long long q[N];

void add(int x,int y,int z){
	ver[++tot].to=y,ver[tot].val=z;
	nxt[tot]=head[x],head[x]=tot;
}

void dfs1(R int x,R int fa){
	dep[x]=dep[fa]+1;
	for(R int i=head[x];i;i=nxt[i]){
		Edge y=ver[i];
		if(y.to!=fa){
			f[y.to][0]=x;
			dis[y.to][0]=y.val;
			for(R int i=1;f[f[y.to][i-1]][i-1];i++){
				f[y.to][i]=f[f[y.to][i-1]][i-1];
				dis[y.to][i]=dis[y.to][i-1]+dis[f[y.to][i-1]][i-1];
			}
			dfs1(y.to,x);
		}
	}
}

Edge upest(R int x,R long long len){
	for(R int i=19;i>=0;i--)
		if(dep[f[x][i]]>1 && dis[x][i]<=len)
			len-=dis[x][i],x=f[x][i];
	return {x,len};
}

bool dfs2(int x,int fa){
	if(b[x] || (x>1 && d[x]==1 && mn[x]<1e18 && dep[x]==2))
		return b[x]=1;
	if(fa && d[x]==1)
		return 0;
	b[x]=1;
	for(R int i=head[x];i;i=nxt[i]){
		Edge y=ver[i];
		if(y.to!=fa)
			b[x]&=dfs2(y.to,x);
	}
	if(b[x] && dep[x]==2 && mn[x]>=dis[x][0] && mn[x]<1e18)
		q[++top]=mn[x]-dis[x][0];
	if(!b[x] && mn[x]<1e18 && dep[x]==2)
		b[x]=1;
	if(x==1){
		/*
		queue<long long> tmp;
		while(q.size()){
			printf("%lld\n",q.top());
			tmp.push(q.top()),q.pop();
		}
		while(tmp.size())
			q.push(tmp.front()),tmp.pop();
		*/
		sort(q+1,q+top+1);
		R int i=head[x];
		for(;i && top;i=nxt[i],top--){
			while(i && b[ver[i].to])
				i=nxt[i];
			if(!i)
				break;
			if(q[top]<ver[i].val)
				break;
		}
		while(i && b[ver[i].to])
			i=nxt[i];
		b[1]=(i==0);
	} 
	return b[x];
}

bool check(long long len){
	for(int i=1;i<=n;i++)
		b[i]=0;
	for(R int i=head[1];i;i=nxt[i])
		mn[ver[i].to]=1e18;
	top=0;
	for(int i=1;i<=m;i++){
		Edge tmp=upest(a[i],len);
		//printf("up:%d %lld\n",tmp.to,tmp.val);
		if(dep[tmp.to]>2)
			b[tmp.to]=1;
		else{
			if(tmp.val<dis[tmp.to][0]){
				b[tmp.to]=1;
				if(mn[tmp.to]<1e18 && mn[tmp.to]>=dis[tmp.to][0])
					q[++top]=(mn[tmp.to]-dis[tmp.to][0]);
				mn[tmp.to]=tmp.val;
			}else if(tmp.val<2*dis[tmp.to][0]){
				if(mn[tmp.to]<=tmp.val)
					q[++top]=(tmp.val-dis[tmp.to][0]);
				else if(mn[tmp.to]<1e18)
					q[++top]=(mn[tmp.to]-dis[tmp.to][0]),mn[tmp.to]=tmp.val;
				else
					mn[tmp.to]=tmp.val;
			}else
				q[++top]=(tmp.val-dis[tmp.to][0]);
			//printf("%lld %lld\n",flag,mn[tmp.to]);
		}
	}
	/*for(int i=1;i<=n;i++)
		printf("%lld ",mn[i]);
	puts("");*/
	bool flag=dfs2(1,0);/*
	for(int i=1;i<=n;i++)
		printf("%d ",b[i]);
	puts("");*/
	return flag;
}

int main(){
	scanf("%d",&n);
	for(R int i=1;i<n;i++){
		scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
		d[edge[i].u]++,d[edge[i].v]++;
	}
	sort(edge+1,edge+n);
	for(R int i=1;i<n;i++)
		add(edge[i].u,edge[i].v,edge[i].w),add(edge[i].v,edge[i].u,edge[i].w);
	scanf("%d",&m);
	for(R int i=1;i<=m;i++)
		scanf("%d",&a[i]);
	if(m<d[1]){
		printf("-1");
		return 0;
	}
	dfs1(1,0);
	if(check(0)){
		printf("0");
		return 0;
	}
	long long l=0,r=5e13;
	while(l<r){
		long long mid=l+r>>1;
		if(check(mid))
			r=mid;
		else
			l=mid+1;
	}
	printf("%lld",l);
	return 0;
}
